# GCN layer (conceptual)
import torch
import torch.nn as nn

class GCNLayer(nn.Module):
    def __init__(self, in_dim, out_dim):
        super().__init__()
        self.linear = nn.Linear(in_dim, out_dim)

    def forward(self, H, A_hat):
        # A_hat: symmetrically normalized adjacency with self-loops
        # A_hat = D̃^{-1/2} Ã D̃^{-1/2}, where Ã = A + I
        return torch.relu(self.linear(A_hat @ H))

from torch_geometric.nn import global_mean_pool

class GraphClassifier(nn.Module):
    def __init__(self, node_feat_dim, hidden_dim, num_classes):
        super().__init__()
        self.conv1 = GINConv(nn.Sequential(
            nn.Linear(node_feat_dim, hidden_dim), nn.ReLU(),
            nn.Linear(hidden_dim, hidden_dim)
        ))
        self.conv2 = GINConv(nn.Sequential(
            nn.Linear(hidden_dim, hidden_dim), nn.ReLU(),
            nn.Linear(hidden_dim, hidden_dim)
        ))
        self.classifier = nn.Linear(hidden_dim, num_classes)

    def forward(self, data):
        x, edge_index, batch = data.x, data.edge_index, data.batch
        x = self.conv1(x, edge_index).relu()
        x = self.conv2(x, edge_index).relu()
        x = global_mean_pool(x, batch)  # [num_graphs, hidden_dim]
        return self.classifier(x)

def message(self, x_j, edge_attr):
    # x_j: [E, node_dim], edge_attr: [E, edge_dim]
    return self.edge_mlp(torch.cat([x_j, edge_attr], dim=-1))

